create table dirkspzm32.isi_etiketten (
    sid                varchar2(2 char) not null enable,
    firma_nr           number(2, 0) not null enable,
    etiketten_name     varchar2(50 char) not null enable,
    rave_report        varchar2(100 char),
    rave_datei         varchar2(255 char),
    etiketten_programm clob
);

alter table dirkspzm32.isi_etiketten
    add constraint pk_isi_etiketten
        primary key ( sid,
                      firma_nr,
                      etiketten_name )
            using index enable;


